return {
  dataType: 'mlb',
  dateInfo: {
    today: 'Monday, August 26, 2024',
    theme: 'Humility & Simplicity',
    dayOfWeek: 'Monday'
  },
  game: {
    score: 'LAD 8, Cincinnati Reds 4',
    gameUrl: 'https://www.mlb.com/dodgers'
  },
  standings: {
    wins: 85,
    losses: 58
  },
  fullRecord: '85-58',
  standingSummary: '1st in NL West'
};

// Alternative Merge - Collect data from both paths manually
// This approach gets data from previous nodes by ID rather than using merge

let aiData = null;
let mlbData = null;

// Try to get AI data from Set AI Data node
try {
  const aiContent = $('Set AI Data').item?.json?.content;
  if (aiContent) {
    aiData = JSON.parse(aiContent);
    console.log('Successfully retrieved AI data');
  }
} catch (e) {
  console.log('Error getting AI data:', e.message);
}

// Try to get MLB data from Set MLB Data node  
try {
  const mlbContent = $('Set MLB Data').item?.json?.content;
  if (mlbContent) {
    mlbData = JSON.parse(mlbContent);
    console.log('Successfully retrieved MLB data');
  }
} catch (e) {
  console.log('Error getting MLB data:', e.message);
}

// Create fallback data if needed
if (!mlbData) {
  console.log('No MLB data found, using fallback');
  mlbData = {
    dateInfo: { today: 'Test Day', theme: 'Test Theme' },
    game: { score: 'No game data' },
    standings: { wins: 0, losses: 0 },
    fullRecord: '0-0'
  };
}

if (!aiData) {
  console.log('No AI data found, using fallback');
  aiData = { text: '{"reflection": "Fallback reflection"}', dataType: 'ai' };
}

// Parse AI content
let spiritual = {};
try {
  const aiText = aiData.text || '{}';
  spiritual = JSON.parse(aiText);
  console.log('Parsed AI content successfully');
} catch (e) {
  console.log('Error parsing AI content:', e.message);
  spiritual = { reflection: 'Fallback spiritual content' };
}

// Create combined output
const result = {
  success: true,
  message: 'Alternative merge successful - no merge node used',
  method: 'direct_node_reference',
  data: {
    aiDataFound: !!aiData,
    mlbDataFound: !!mlbData,
    spiritualReflection: spiritual.reflection || 'No reflection',
    gameScore: mlbData.game?.score || 'No game score',
    todaysDate: mlbData.dateInfo?.today || 'No date',
    combinedData: {
      ai: aiData,
      mlb: mlbData
    }
  }
};

console.log('Alternative merge result:', JSON.stringify(result, null, 2));

return result;
